const store = $getWorkflowStaticData('global');

if (!store.pwHash) {
  store.pwHash = '50d71f9f961711ffced0db1f0dbc8c0ccf654ac9a22695b62591a82ede4e4e1f';
}

const body = $input.first().json.body ?? $input.first().json;
const { currentHash, newHash } = body;

if (!currentHash || !newHash) return [{ json: { success: false, error: 'Missing fields' } }];
if (currentHash !== store.pwHash) return [{ json: { success: false, error: 'Wrong current password' } }];
if (newHash.length !== 64) return [{ json: { success: false, error: 'Invalid hash' } }];

store.pwHash = newHash;
return [{ json: { success: true } }];
